def main():
    H, W = map(int, input().split())
    total_area = H * W

    min_diff = float('inf')

    # Case 1: 2 horizontal cuts (split height into 3 parts)
    for h1 in range(1, H):
        for h2 in range(1, H - h1):
            h3 = H - h1 - h2
            if h3 <= 0:
                continue
            areas = [h1 * W, h2 * W, h3 * W]
            diff = max(areas) - min(areas)
            min_diff = min(min_diff, diff)

    # Case 2: 2 vertical cuts (split width into 3 parts)
    for w1 in range(1, W):
        for w2 in range(1, W - w1):
            w3 = W - w1 - w2
            if w3 <= 0:
                continue
            areas = [H * w1, H * w2, H * w3]
            diff = max(areas) - min(areas)
            min_diff = min(min_diff, diff)

    # Case 3: 1 horizontal + 1 vertical cut 
    # A horizontal cut at h1, then cut the top piece (h1×W) vertically
    for h1 in range(1, H):
        for w1 in range(1, W):
            w2 = W - w1
            if w2 <= 0:
                continue
            areas = [h1 * w1, h1 * w2, (H - h1) * W]
            diff = max(areas) - min(areas)
            min_diff = min(min_diff, diff)

    # Case 4: 1 horizontal + 1 vertical cut
    # A horizontal cut at h1, then cut the bottom piece ((H-h1)×W) vertically
    for h1 in range(1, H):
        for w1 in range(1, W):
            w2 = W - w1
            if w2 <= 0:
                continue
            areas = [(H - h1) * w1, (H - h1) * w2, h1 * W]
            diff = max(areas) - min(areas)
            min_diff = min(min_diff, diff)

    print(min_diff)

